; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger || f.saveIsForbidden

@eval exp='f.saveIsForbidden = false'
@notice text="Moving Floor Hall" cond='game.onObjectTrigger'

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] party.lastIsMove

@eval exp='f.saveIsForbidden = true'
@wait time=200
@walk turn=e
@wait time=200
@se f=dragstone
[iscript]
for(var y = 2; y <= 8; y += 2)
{
	for(var x = 2; x <= 7; x++)
	{
		game.map.changeObject(%[type: "air", trap: "air", img: void], x, y, "f");
	}
	game.map.changeObject(%[type: "floor", trap: void, img: "soilr"], intrandom(2, 7), y, "f");
}
[endscript]
@wait time=1000
@playse storage=rockdrop
@wait time=500
@notice text="I heard something heavy moving across the floor!"

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] f.saveIsForbidden

@eval exp='f.saveIsForbidden = false'

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@notice text="Which door is the correct one?"

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] onObjectTrigger

@notice text="The path to the audience chamber will not be opened to those who do not have the ability to see ahead."

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] onObjectTrigger

@barrel
@eval exp='game.curTarget.addParam("intellect", 1)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Intelligence permanently increased by 1!"'

[eventoff]
;-------------------------------------------------------------------------------
